const express = require('express');
const winston = require('winston');
const path = require('path');

// Create logger with file transport
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

const app = express();

// Middleware to parse JSON bodies
app.use(express.json());

// Custom logging middleware
app.use((req, res, next) => {
  const startTime = Date.now();
  
  // Capture user data
  const username = req.headers['x-username'] || 'anonymous';
  const ipAddress = req.ip || req.connection.remoteAddress || 'unknown';
  const userAgent = req.headers['user-agent'] || 'unknown';
  const customHeader = req.headers['x-custom-header'] || 'none';
  
  // Log request
  logger.info('HTTP Request', {
    method: req.method,
    url: req.url,
    username: username,
    ipAddress: ipAddress,
    userAgent: userAgent,
    customHeader: customHeader,
    timestamp: new Date().toISOString()
  });
  
  // Log response
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    logger.info('HTTP Response', {
      method: req.method,
      url: req.url,
      statusCode: res.statusCode,
      duration: duration,
      username: username,
      ipAddress: ipAddress,
      timestamp: new Date().toISOString()
    });
  });
  
  next();
});

// Route to accept user input
app.post('/audit', (req, res) => {
  try {
    const { message, data } = req.body;
    
    // Sanitize user input to prevent log injection
    const sanitizedMessage = sanitizeInput(message);
    const sanitizedData = sanitizeInput(data);
    
    // Log user input
    logger.info('User Input', {
      message: sanitizedMessage,
      data: sanitizedData,
      timestamp: new Date().toISOString(),
      username: req.headers['x-username'] || 'anonymous',
      ipAddress: req.ip || req.connection.remoteAddress || 'unknown'
    });
    
    res.status(200).json({ 
      status: 'success',
      message: 'Input logged successfully'
    });
  } catch (error) {
    logger.error('Error processing audit input', {
      error: error.message,
      timestamp: new Date().toISOString()
    });
    res.status(500).json({ 
      status: 'error',
      message: 'Internal server error'
    });
  }
});

// Route to get audit logs
app.get('/audit', (req, res) => {
  try {
    const logFilePath = path.join(__dirname, 'audit.log');
    const fs = require('fs');
    
    fs.readFile(logFilePath, 'utf8', (err, data) => {
      if (err) {
        logger.error('Error reading audit log file', {
          error: err.message,
          timestamp: new Date().toISOString()
        });
        return res.status(500).json({ 
          status: 'error',
          message: 'Failed to read audit logs'
        });
      }
      
      const logs = data.split('\n').filter(line => line.trim() !== '');
      const parsedLogs = logs.map(line => {
        try {
          return JSON.parse(line);
        } catch (e) {
          return { raw: line };
        }
      });
      
      res.status(200).json({ 
        status: 'success',
        logs: parsedLogs
      });
    });
  } catch (error) {
    logger.error('Error retrieving audit logs', {
      error: error.message,
      timestamp: new Date().toISOString()
    });
    res.status(500).json({ 
      status: 'error',
      message: 'Failed to retrieve audit logs'
    });
  }
});

// Sanitization function to prevent log injection
function sanitizeInput(input) {
  if (typeof input !== 'string') {
    return String(input);
  }
  
  // Remove or escape potentially dangerous characters
  return input
    .replace(/\n/g, ' ')
    .replace(/\r/g, ' ')
    .replace(/\t/g, ' ')
    .replace(/"/g, '\\"')
    .replace(/'/g, "\\'");
}

// Error handling middleware
app.use((err, req, res, next) => {
  logger.error('Unhandled error', {
    error: err.message,
    stack: err.stack,
    timestamp: new Date().toISOString(),
    username: req.headers['x-username'] || 'anonymous',
    ipAddress: req.ip || req.connection.remoteAddress || 'unknown'
  });
  
  res.status(500).json({ 
    status: 'error',
    message: 'Internal server error'
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Audit logging server running on port ${PORT}`);
});

module.exports = app;